mapper.select:
with candidates as (
  select outbox_id from module_outbox_events
  where status='PENDING'
     or (status='RETRY_WAITING' and (next_attempt_at is null or next_attempt_at <= #{now}))
     or (status='DISPATCHING' and (claim_until is null or claim_until <= #{now}))
  order by created_at asc for update skip locked limit #{limit}
)
update module_outbox_events e set status='DISPATCHING',claimed_by=#{workerId},claim_until=#{claimUntil},updated_at=#{now}
from candidates c where e.outbox_id=c.outbox_id returning e.*
